dslRuleAfterChange:
new java.lang.IllegalArgumentException() :: caughtException($e)
=> new java.lang.IllegalArgumentException($e)
;;

new java.lang.IllegalArgumentException($msg) :: caughtException($e)
=> new java.lang.IllegalArgumentException($msg, $e)
;;

dslRule:
@id: jdt.internal.modulebinding.field-to-getter
@description: Replace direct field access to internal ModuleBinding.uses with its getter method.
@severity: info
getTypes($compilerBinding.uses) :: instanceof($compilerBinding, "org.eclipse.jdt.internal.compiler.lookup.ModuleBinding") && sourceVersionGE(9)
=> getTypes($compilerBinding.getUses())
;;
